var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"실망스럽구나.","JPN":"まことに残念だ。","ENG":"How disappointing.","TWN":"真讓人失望。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"마왕의 권능을 등에 업고도, 인간에게 패배하여 꼴사납게 도망쳐 오다니.","JPN":"魔王の権能があるにも関わらず、人間に敗北し見苦しく逃げてくるなど。","ENG":"Even with the Demon Lord's power, you lost to a human and fled.","TWN":"就算背靠魔王的權能，竟然還會敗給人類，狼狽地逃回來。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"면목 없군요. 인간들의 곁을 지키는 자가 악마일 줄은 몰랐습니다.","JPN":"面目ありません。人間たちのそばを守っている者が悪魔だとは知りませんでしたので。","ENG":"I apologize for my actions. I did not know that the one guarding the humans was a devil.","TWN":"真是無地自容。沒想到守護在人類身邊的竟然是魔鬼。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그래. 진작에 죽었어야 할 황금나무가 한낱 악마에게 쓰임 당하고 있었다는 건 뜻밖이군.","JPN":"ああ。とうに死んでいるはずの黄金の木が一介の悪魔に利用されていたのは予想外であるな。","ENG":"Yes. It is unexpected to hear that a mere devil is using the Golden Tree that should have died long ago as her own.","TWN":"哼哼，早該枯死的黃金樹竟然被一個魔鬼利用，真是出乎意料。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하지만 지금은 밑동만 남은 그루터기일 뿐. 옛 황금나무의 위상에 비할 바는 아니겠지.","JPN":"だが、今は根本だけの切り株にすぎん。昔の黄金の木とは比べるまでもない。","ENG":"Nevertheless, all that remains of it is the stump. It is nothing compared to the Golden Tree of the old days.","TWN":"但現在它不過是個只剩木墩的殘骸，無法與昔日的黃金樹相提並論。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"물론입니다. 무엇보다 마왕께선 한낱 신성을 잃은 그 나무보다 더 본질적인 힘을 갖고 계시니까요.","JPN":"もちろんです。何より魔王は神聖さを無くしたあの木より、本質的な力をお持ちですから。","ENG":"Of course. Above all, the Demon Lord possesses greater intrinsic power than the tree that has lost its divinity.","TWN":"那是當然，魔王大人擁有的可是比那失去神性的枯樹更為本質的力量。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"동생이 직접 나설 일은 없을 거다. 내가 놈들을 짓밟고, 비루한 꼴로 연명하는 그 나무를 뿌리째 잘라낼 테니.","JPN":"妹が直接手を下すまでもない。余がやつらを踏みつけ、滑稽な姿で延命するあの木を根元ごと引き抜いてやろうではないか。","ENG":"My sister will not need to take care of them. I shall trample them myself and relieve the tree from its miserable state by cutting its roots.","TWN":"妹妹她是不會親自出手的。我會親自踏平那些廢物，把那棵苟延殘喘的樹連根拔起。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"인류의 보루를 찾아낸 상으로, 널 처벌하진 않으마.","JPN":"人類の要塞を探し出した褒美として、貴様への罰は取り消してやろう。","ENG":"As a reward for finding humanity's stronghold, I will not punish you.","TWN":"作為找到人類的獎勵，我將免除你的責罰。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"지금쯤 엘리시온에 묻힌 성자들이 망집이 되어 깨어났을 거다.","JPN":"そろそろエリシオンに埋まっている聖者たちが執念により目覚める頃だろう。","ENG":"By now, the Helgons buried in Elysion should have awakened as obsessions.","TWN":"此刻埋葬在艾利森的聖者們應該已經化作怨靈甦醒過來。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"넌 돌아가서 그것들에게 죽음보다 더한 고통을 주고…","JPN":"貴様は戻り、それらに死よりもつらい苦痛を与え……","ENG":"You, go back to them and give them a worse pain than death...","TWN":"你回去讓它們體驗比死亡更痛苦的折磨…"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"없애버려라.","JPN":"殺せ。","ENG":"Afterwards, get rid of them.","TWN":"然後，消滅它們。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"뜻밖이군요. 성자의 망집을 길들이면 마왕의 군세에도 제법 보탬이 될 텐데요.","JPN":"意外ですね。聖者たちを支配下におけば、魔王の軍勢にも役立つはずですが。","ENG":"How unexpected. For taming the obsessions of the Helgons could greatly aid your army.","TWN":"真是意外。如果能馴服聖者的怨靈，對魔王的軍隊也會有很大幫助吧。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"놈들에게 황금가지가 있는 한, 그 녀석들의 악기는 그저 잔재주일 뿐이다.","JPN":"やつらに黄金の枝があるかぎり、あやつらの楽器はただの小細工にすぎん。","ENG":"As long as the Stump has the Golden Branch, their instruments will be nothing but cheap tricks.","TWN":"只要擁有金枝，那些傢伙的樂器不過是些小把戲。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"잔말 말고 명령에 따라라, 삼하인.","JPN":"さっさと命令に従え、サウィン。","ENG":"Stop wasting your breath and do as you are ordered, Samhain.","TWN":"別廢話，按命令行事，薩溫。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"…알겠습니다. 그리 하죠.","JPN":"……承知しました。そういたしましょう。","ENG":"...Understood. As you command.","TWN":"…是，遵命。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"왕의 사도이시여.","JPN":"王の使徒よ。","ENG":"Oh, Apostle of the queen.","TWN":"王的使徒。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"부디 세상의 종말과 함께, 영광스러운 귀환을.","JPN":"どうか世界の終末とともに、光栄なる帰還を。","ENG":"Bring us a glorious return with the end of the world.","TWN":"願你與世界的終結一同，榮耀歸來。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EXPLORER_ROOT_NPC_NULL","text":{"KOREA":"입구가 보입니다! 저 하수도 안에 저희가 찾는 적철이 있을 거예요!","JPN":"入口が見えます！　あの下水道の中に私たちが探している赤鉄があるはずです！","ENG":"I see the entrance! The Violarite we are looking for should be in those sewers!","TWN":"看到入口了！在那個下水道裡，我們要找的赤鐵應該就在裡面！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"EXPLORER_ROOT_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"역시 마물들이 지키고 있군요. 진입하려면 시선을 끄는 편이 좋겠습니다.","JPN":"やはり魔物たちが守っていますね。侵入するにはやつらの気を引いた方が良さそうです。","ENG":"As expected, the monsters are guarding it. We will need a distraction in order to gain entry.","TWN":"果然有怪物在守衛。要進去的話，最好引開它們的注意力。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"제가 유인할게요. 그동안 여러분은 안을 살펴봐주세요.","JPN":"私がおびき寄せます。その間にみなさんは中を探してください。","ENG":"I'll lure them away. In the meanwhile, you all should take a look inside.","TWN":"我來引開它們，你們趁機進去看看情況。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"저런 부류의 마물들은 두 다리로 따돌리긴 힘들 겁니다.","JPN":"あの種類の魔物を人の足で撒くのは難しいでしょう。","ENG":"Those types of monsters will be difficult to outrun with only two legs.","TWN":"那種類型的怪物，光靠兩條腿是甩不掉的。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"괜찮다면, 이번엔 아이단과 함께 가시죠.","JPN":"よかったら、アイダンを使ってください。","ENG":"If it will be no trouble, take Aidan with you.","TWN":"如果可以的話，這次和艾丹一起去吧。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"윽… 말이요? 그치만 전 승마 같은 건 배운 적 없는데요?","JPN":"うっ……馬ですか？　でも、私は乗馬なんて教えてもらったことないですよ？","ENG":"Ngh... the horse? But I've never learned how to ride one.","TWN":"呃…騎馬嗎？可是我從來沒學過騎馬？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"괜찮습니다.","JPN":"大丈夫です。","ENG":"Not to worry.","TWN":"沒關係。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COACHMAN_ROOT_NPC_NULL","text":{"KOREA":"이 친구는 술에 취해 인사불성이 된 제사장님도 자주 모셔왔으니까요.","JPN":"こいつは酒に酔ってフラフラになった祭祀長もよく乗せていました。","ENG":"As this one here has frequently brought even the piss-drunk High Priest home safe.","TWN":"這匹馬經常載著喝醉酒的祭司長，所以沒問題的。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};